import React, { useState } from 'react'

export default function Msg(props) {
  let _name = props.text;
  let _theme = props.theme;
 
 let styleTheme = 
  _theme==="red"?{backgroundColor:"#fce8e6", color:"firebrick"}:
  _theme==="green"?{backgroundColor:"rgba(230,244,234,1)", color:"rgba(24,128,56,1)"}:
  _theme==="yellow"?{backgroundColor:"rgba(255,249,233,1)", color:"rgba(255,202,40,1)"}:
  _theme==="blue"?{backgroundColor:"#E7EDF6", color:"#174ea6"}:{};

  return (
      <div className={`msg_alert _dsplFlx btc_color `} style={styleTheme}>
        <div className={`msg_alert_title ${props.multiline?"multiline":""}`}>
        {_name} 
        </div>
        <div className={`flexSpace`}/>                    
      </div>

    )
}
